import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Gift } from 'lucide-react';
import { SharpButton } from './ui/SharpButton';
import { COIN_REWARDS } from '../types';

interface SpinWheelProps {
  isOpen: boolean;
  onClose: () => void;
  onReward: (amount: number) => void;
}

export const SpinWheel: React.FC<SpinWheelProps> = ({ isOpen, onClose, onReward }) => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [rotation, setRotation] = useState(0);
  const [result, setResult] = useState<number | null>(null);

  const handleSpin = () => {
    if (isSpinning) return;
    setIsSpinning(true);
    setResult(null);

    const randomIndex = Math.floor(Math.random() * COIN_REWARDS.length);
    const reward = COIN_REWARDS[randomIndex];
    const segmentAngle = 360 / COIN_REWARDS.length;
    const fullSpins = 360 * (5 + Math.floor(Math.random() * 3));
    const targetRotation = fullSpins - (randomIndex * segmentAngle);

    setRotation(targetRotation);

    setTimeout(() => {
      setIsSpinning(false);
      setResult(reward);
      onReward(reward);
    }, 4000);
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-[150] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 overflow-y-auto"
        >
          <motion.div 
            initial={{ scale: 0.8, y: 50, opacity: 0 }}
            animate={{ scale: 1, y: 0, opacity: 1 }}
            exit={{ scale: 0.8, y: 50, opacity: 0 }}
            className="relative bg-ludo-dark border-4 border-ludo-yellow p-6 md:p-8 w-full max-w-sm flex flex-col items-center gap-6 shadow-[0_0_50px_rgba(255,165,2,0.3)] my-auto"
            style={{ borderRadius: 0 }}
          >
            <button 
              onClick={onClose}
              disabled={isSpinning}
              className="absolute top-4 right-4 text-white/50 hover:text-white transition-colors disabled:opacity-30"
            >
              <X size={24} />
            </button>

            <div className="text-center">
              <h2 className="text-2xl font-black text-white uppercase tracking-widest mb-1 italic">Daily Spin</h2>
              <p className="text-ludo-yellow text-[10px] font-mono uppercase tracking-widest">Override Randomness</p>
            </div>

            <div className="relative w-48 h-48 md:w-64 md:h-64 flex-shrink-0">
              <div className="absolute -top-3 left-1/2 -translate-x-1/2 z-20 text-white drop-shadow-lg">
                <div className="w-6 h-6 bg-white rotate-45 border-4 border-ludo-dark translate-y-2" />
              </div>

              <div 
                className="w-full h-full rounded-full border-4 border-white overflow-hidden relative shadow-2xl"
                style={{ 
                  transform: `rotate(${rotation}deg)`,
                  transition: 'transform 4s cubic-bezier(0.15, 0, 0, 1)'
                }}
              >
                <div className="absolute inset-0 rounded-full" 
                     style={{ 
                       background: `conic-gradient(
                         #FF4757 0deg 60deg, 
                         #2ED573 60deg 120deg, 
                         #1E90FF 120deg 180deg, 
                         #FFA502 180deg 240deg, 
                         #FF4757 240deg 300deg, 
                         #2ED573 300deg 360deg
                       )`
                     }} 
                />
                 {COIN_REWARDS.map((amount, index) => (
                    <div 
                      key={index}
                      className="absolute w-full h-full top-0 left-0 text-center pt-4 md:pt-6 font-black text-white text-base md:text-lg drop-shadow-md"
                      style={{ transform: `rotate(${index * (360/6)}deg)` }}
                    >
                      <span className="block">{amount > 0 ? amount : '☹️'}</span>
                    </div>
                 ))}
              </div>

              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-12 h-12 md:w-16 md:h-16 bg-white rounded-full z-10 flex items-center justify-center border-4 border-ludo-dark shadow-inner">
                 <Gift className="text-ludo-red w-6 h-6 md:w-8 md:h-8" />
              </div>
            </div>

            <div className="h-12 flex items-center justify-center w-full text-center">
              {result !== null ? (
                <motion.div 
                  initial={{ scale: 0 }} 
                  animate={{ scale: 1 }}
                  className="text-lg md:text-xl font-black text-ludo-yellow uppercase tracking-tighter italic"
                >
                  {result === 0 ? "Empty Node!" : `Won ${result} HC!`}
                </motion.div>
              ) : (
                 <p className="text-white/30 text-[9px] font-black uppercase tracking-widest">{isSpinning ? "Logic Executing..." : "Ignite the Wheel"}</p>
              )}
            </div>

            <SharpButton 
              onClick={handleSpin} 
              disabled={isSpinning || result !== null}
              className="w-full h-12 md:h-14"
              variant="accent"
            >
              {isSpinning ? 'Executing...' : result !== null ? 'Collect' : 'Ignite'}
            </SharpButton>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Calendar, Check, Gift, Star } from 'lucide-react';
import { SharpButton } from './ui/SharpButton';
import { HomiieCoin } from './icons/HomiieCoin';

interface DailyRewardOverlayProps {
  isOpen: boolean;
  onClose: () => void;
  onClaim: (amount: number) => void;
}

const REWARDS = [100, 200, 500, 1000, 2500, 5000, 10000];

export const DailyRewardOverlay: React.FC<DailyRewardOverlayProps> = ({ isOpen, onClose, onClaim }) => {
  const [streak, setStreak] = useState(1);
  const [lastClaimed, setLastClaimed] = useState<number | null>(null);
  const [canClaim, setCanClaim] = useState(false);

  useEffect(() => {
    const savedStreak = localStorage.getItem('homiie_streak');
    const savedLastClaimed = localStorage.getItem('homiie_last_claimed');

    if (savedStreak) setStreak(parseInt(savedStreak));
    if (savedLastClaimed) setLastClaimed(parseInt(savedLastClaimed));

    const checkClaimStatus = () => {
      if (!savedLastClaimed) {
        setCanClaim(true);
        return;
      }

      const now = new Date();
      const last = new Date(parseInt(savedLastClaimed));

      const isSameDay = now.toDateString() === last.toDateString();

      // Calculate day difference
      const diffTime = Math.abs(now.getTime() - last.getTime());
      const diffDays = diffTime / (1000 * 60 * 60 * 24);

      if (diffDays >= 2) {
        // Streak broken
        setStreak(1);
        localStorage.setItem('homiie_streak', '1');
        setCanClaim(true);
      } else if (!isSameDay) {
        setCanClaim(true);
      } else {
        setCanClaim(false);
      }
    };

    checkClaimStatus();
  }, [isOpen]);

  const handleClaim = () => {
    const amount = REWARDS[streak - 1];
    onClaim(amount);

    const now = new Date().getTime();
    const nextStreak = streak >= 7 ? 1 : streak + 1;

    setLastClaimed(now);
    setCanClaim(false);
    setStreak(nextStreak);

    localStorage.setItem('homiie_last_claimed', now.toString());
    localStorage.setItem('homiie_streak', nextStreak.toString());

    setTimeout(onClose, 1000);
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-ludo-dark/95 backdrop-blur-md overflow-y-auto"
        >
          <motion.div 
            initial={{ scale: 0.95, y: 20 }}
            animate={{ scale: 1, y: 0 }}
            exit={{ scale: 0.95, y: 20 }}
            className="bg-ludo-dark border border-white/10 w-full max-w-sm relative rounded-none shadow-2xl p-6 md:p-8 my-auto"
          >
            <button onClick={onClose} className="absolute top-4 right-4 text-white/30 hover:text-white transition-all">
              <X size={20} />
            </button>

            <div className="text-center mb-8">
              <h2 className="text-2xl font-black text-white uppercase tracking-tighter italic">Daily Protocol</h2>
              <p className="text-[9px] font-mono text-ludo-yellow uppercase tracking-[0.3em] mt-1">Sequence Day {streak}</p>
            </div>

            <div className="grid grid-cols-4 gap-2 mb-8">
              {REWARDS.map((amount, idx) => {
                const day = idx + 1;
                const isCompleted = day < streak;
                const isCurrent = day === streak;

                return (
                  <div 
                    key={idx}
                    className={clsx(
                      "aspect-square flex flex-col items-center justify-center gap-1 border transition-all relative overflow-hidden",
                      isCompleted ? "bg-ludo-green/10 border-ludo-green/30 opacity-40" : 
                      isCurrent ? "bg-white/5 border-ludo-yellow shadow-[0_0_15px_rgba(255,165,2,0.2)]" : 
                      "bg-white/[0.02] border-white/5 opacity-30",
                      day === 7 ? "col-span-2 aspect-auto h-full" : ""
                    )}
                  >
                    <span className="text-[8px] font-black uppercase text-white/40">D{day}</span>
                    <div className="relative">
                      {isCompleted ? <Check size={14} className="text-ludo-green" /> : <HomiieCoin size={16} />}
                    </div>
                    <span className={clsx("text-[9px] font-black font-mono", isCurrent ? "text-ludo-yellow" : "text-white/60")}>
                      {amount}
                    </span>
                    {day === 7 && <Star size={8} className="absolute top-1 right-1 text-ludo-yellow fill-ludo-yellow" />}
                  </div>
                );
              })}
            </div>

            <div className="flex flex-col gap-2">
              <SharpButton 
                onClick={handleClaim} 
                disabled={!canClaim}
                variant={canClaim ? "primary" : "outline"}
                className="w-full h-12"
              >
                {canClaim ? `Claim ${REWARDS[streak-1]} HC` : "Protocol Locked"}
              </SharpButton>
              <p className="text-center text-[8px] font-mono text-white/20 uppercase tracking-widest">Reset occurs if sequence is broken</p>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

