    setIsSpinning(true);
    setResult(null);
    setShowWinMessage(false);

    const randomIndex = Math.floor(Math.random() * COIN_REWARDS.length);
    const reward = COIN_REWARDS[randomIndex];
    const segmentAngle = 360 / COIN_REWARDS.length;
    // We want to land in the middle of the segment
    const segmentCenter = segmentAngle / 2;
    const fullSpins = 360 * (6 + Math.floor(Math.random() * 4));
    const targetRotation = fullSpins + (randomIndex * segmentAngle);

    // Using a negative rotation or adjusting to ensure it lands on the right index clockwise
    // The rotation logic should align with the index mapping
    setRotation(prev => prev + targetRotation);

    setTimeout(() => {
      setIsSpinning(false);
      setResult(reward);
      setShowWinMessage(true);
      onReward(reward);
    }, 4000);
  };

  const canAfford = userCoins >= SPIN_COST;

