                     }} 
                />

                {/* Visual Segment Lines */}
                {[0, 60, 120, 180, 240, 300].map(deg => (
                  <div 
                    key={deg} 
                    className="absolute top-1/2 left-1/2 w-[50%] h-[2px] bg-black/20 origin-left"
