              {/* Center Hub */}
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-14 h-14 md:w-16 md:h-16 bg-[#0a0a0c] rounded-full z-10 flex items-center justify-center border-4 border-[#1a1a1e] shadow-2xl">
