      {view !== ViewState.GAME && view !== ViewState.WALLET && view !== ViewState.AUTH && (
        <div className="absolute bottom-4 left-6 text-white/20 font-mono text-xs z-10 pointer-events-none">
          v1.0.0 • BETA
        </div>
