import { COIN_REWARDS } from '../types';
import { HomiieCoin } from './icons/HomiieCoin';

interface SpinWheelProps {
  isOpen: boolean;
  onClose: () => void;
  onReward: (amount: number) => void;
  onDeduct: (amount: number) => boolean;
  userCoins: number;
}

const SPIN_COST = 100;

export const SpinWheel: React.FC<SpinWheelProps> = ({ isOpen, onClose, onReward, onDeduct, userCoins }) => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [rotation, setRotation] = useState(0);
  const [result, setResult] = useState<number | null>(null);
  const [showWinMessage, setShowWinMessage] = useState(false);

  const handleSpin = () => {
    if (isSpinning) return;

    // Attempt to deduct cost
    const success = onDeduct(SPIN_COST);
    if (!success) return;

    setIsSpinning(true);
    setResult(null);
    setShowWinMessage(false);

    // Calculate random reward
    const randomIndex = Math.floor(Math.random() * COIN_REWARDS.length);
    const reward = COIN_REWARDS[randomIndex];

    const segmentAngle = 360 / COIN_REWARDS.length;
    const fullSpins = 360 * (6 + Math.floor(Math.random() * 4));

    /**
     * Calculation Logic:
     * To make segment [randomIndex] land at the top (0 deg):
     * The wheel must be rotated by (360 - (randomIndex * segmentAngle)) degrees.
     * We add fullSpins to make it spin multiple times.
     * We calculate relative to current rotation to ensure it always spins forward.
     */
    const currentOffset = rotation % 360;
