                <div className="w-full h-1 bg-white/5 overflow-hidden rounded-full">
                   <motion.div 
                     key={timerKey} 
                     className={clsx("h-full", bgStyles[player.color])} 
                     initial={{ width: "100%" }} 
                     animate={{ width: "0%" }} 
