interface GameScreenProps {
  onExit: () => void;
  vsComputer?: boolean;
}

const TURN_DURATION = 15000; // 15 seconds
const MOVE_STEP_DELAY = 180; // Snappier movement

export const GameScreen: React.FC<GameScreenProps> = ({ onExit, vsComputer = false }) => {
  // --- Game State ---
  const [players, setPlayers] = useState<PlayerState[]>([
    { 
      id: 'p1', name: 'You', color: 'red', avatarUrl: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Felix', 
      isBot: false, 
      pawns: [0,1,2,3].map(i => ({ id: `red-${i}`, color: 'red', location: -1 })) 
    },
    { 
      id: 'p2', name: vsComputer ? 'Bot Blue' : 'Player 2', color: 'blue', avatarUrl: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Sarah', 
      isBot: vsComputer, 
      pawns: [0,1,2,3].map(i => ({ id: `blue-${i}`, color: 'blue', location: -1 })) 
    },
    { 
      id: 'p3', name: vsComputer ? 'Bot Yellow' : 'Player 3', color: 'yellow', avatarUrl: 'https://api.dicebear.com/7.x/avataaars/svg?seed=John', 
      isBot: vsComputer, 
      pawns: [0,1,2,3].map(i => ({ id: `yellow-${i}`, color: 'yellow', location: -1 })) 
    },
    { 
      id: 'p4', name: vsComputer ? 'Bot Green' : 'Player 4', color: 'green', avatarUrl: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Aneka', 
      isBot: vsComputer, 
      pawns: [0,1,2,3].map(i => ({ id: `green-${i}`, color: 'green', location: -1 })) 
    },
  ]);

  const [turnIndex, setTurnIndex] = useState(0);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [hasRolled, setHasRolled] = useState(false);
  const [validMovePawns, setValidMovePawns] = useState<string[]>([]);

  // Game Status
  const [isGameOver, setIsGameOver] = useState(false);
  const [turnTimerKey, setTurnTimerKey] = useState(0);
  const [isMovingPawn, setIsMovingPawn] = useState(false);
  const [pawnCelebration, setPawnCelebration] = useState<{ color: PlayerColor, pawnId: string } | null>(null);

  // --- Secret DIY State ---
  const [diyUnlocked, setDiyUnlocked] = useState(false);
  const [diyActive, setDiyActive] = useState(false);
  const [showDiyPopup, setShowDiyPopup] = useState(false);
  const diySelectedRef = useRef<number | null>(null);

  const currentPlayer = players[turnIndex];

  // Helper to get number of finished players
  const getFinishedCount = useCallback(() => {
    return players.filter(p => p.rank).length;
  }, [players]);

  // --- Core Game Logic ---
  const nextTurn = useCallback(() => {
    if (getFinishedCount() >= 3) {
      setIsGameOver(true);
      return;
    }

    setHasRolled(false);
    setValidMovePawns([]);
    setTurnTimerKey(prev => prev + 1);
    setIsMovingPawn(false);

    setTurnIndex(prevIndex => {
      let nextIndex = (prevIndex + 1) % 4;
      let loopCount = 0;

      while (players[nextIndex].rank && loopCount < 4) {
        nextIndex = (nextIndex + 1) % 4;
        loopCount++;
      }

      if (loopCount >= 4) return prevIndex;
      if (diceValue === 6 && !players[prevIndex].rank) {
         return prevIndex;
      }
      return nextIndex;
    });
  }, [diceValue, players, getFinishedCount]);

  const handleRoll = useCallback(() => {
    if (isRolling || hasRolled || isGameOver || isMovingPawn || currentPlayer.rank) return;
    setIsRolling(true);
    if (diyActive) {
      setShowDiyPopup(true);
      diySelectedRef.current = null;
    }
    const rollDuration = diyActive ? 1200 : 600; 
    setTimeout(() => {
      let rolledValue = Math.floor(Math.random() * 6) + 1;
      if (diyActive) {
        setShowDiyPopup(false);
        if (diySelectedRef.current !== null) {
          rolledValue = diySelectedRef.current;
        }
      }
      setDiceValue(rolledValue);
      setIsRolling(false);
      setHasRolled(true);
      const moves: string[] = [];
      currentPlayer.pawns.forEach(pawn => {
        if (isValidMove(pawn.location, rolledValue)) {
          moves.push(pawn.id);
        }
      });
      setValidMovePawns(moves);
      if (moves.length === 0) {
        setTimeout(nextTurn, 1000);
      }
    }, rollDuration);
  }, [currentPlayer, isRolling, hasRolled, isGameOver, isMovingPawn, nextTurn, diyActive]);

  const handleDiySelect = (value: number) => {
    diySelectedRef.current = value;
  };

  const handlePawnClick = (playerId: string, pawnId: string) => {
    if (!hasRolled || playerId !== currentPlayer.id || !validMovePawns.includes(pawnId) || isMovingPawn) return;
    animateMoveSequence(pawnId);
  };

  const setPawnLocation = (pawnId: string, newLoc: number) => {
    setPlayers(prevPlayers => {
      return prevPlayers.map(player => {
        if (player.id !== currentPlayer.id) return player;
        return {
          ...player,
          pawns: player.pawns.map(pawn => 
            pawn.id === pawnId ? { ...pawn, location: newLoc } : pawn
          )
        };
      });
    });
  };

  const animateMoveSequence = useCallback(async (pawnId: string) => {
    setIsMovingPawn(true);
    const player = players.find(p => p.id === currentPlayer.id);
    const pawn = player?.pawns.find(p => p.id === pawnId);
    if (!player || !pawn) return;

    const currentLoc = pawn.location;
    const stepsToMove = (currentLoc === -1) ? 1 : diceValue;

    for (let i = 1; i <= stepsToMove; i++) {
        let nextLoc = (currentLoc === -1) ? 0 : (currentLoc + i);

        // Handle Home Logic (57 = 99)
        if (nextLoc >= 57) {
          nextLoc = 99;
          setPawnLocation(pawnId, nextLoc);
          break; // Reach home immediately if it exceeds path
        }

        setPawnLocation(pawnId, nextLoc);
        await new Promise(resolve => setTimeout(resolve, MOVE_STEP_DELAY));
    }

    // Final calculations after all steps are processed
    let finalLocation = (currentLoc === -1) ? 0 : (currentLoc + diceValue);
    if (finalLocation >= 57) finalLocation = 99;

    setPlayers(prev => {
      const newPlayers = [...prev];
      const currentPlayerIdx = newPlayers.findIndex(p => p.id === player.id);

      // Capture Logic
      if (finalLocation < 51) { 
        const offset = PLAYER_START_OFFSETS[player.color];
        const globalPos = (offset + finalLocation) % 52;
        const isSafe = SAFE_INDICES.includes(globalPos);

        if (!isSafe) {
           newPlayers.forEach((opp, oppIdx) => {
              if (opp.id !== player.id && !opp.rank) {
                  opp.pawns.forEach((oppPawn, oppPawnIdx) => {
                      const oppOffset = PLAYER_START_OFFSETS[opp.color];
                      const oppGlobal = oppPawn.location !== -1 && oppPawn.location < 51 
                          ? (oppOffset + oppPawn.location) % 52 
                          : -999;

                      if (globalPos === oppGlobal) {
                          newPlayers[oppIdx].pawns[oppPawnIdx].location = -1;
                      }
                  });
              }
           });
        }
      }

      // Check if pawn just reached home
      if (finalLocation === 99) {
         setPawnCelebration({ color: player.color, pawnId: pawnId });
         setTimeout(() => setPawnCelebration(null), 2500);
      }

      // Win Condition
      const hasWonNow = newPlayers[currentPlayerIdx].pawns.every(p => p.location === 99);
      if (hasWonNow && !newPlayers[currentPlayerIdx].rank) {
         const finishedCount = newPlayers.filter(p => p.rank).length;
         newPlayers[currentPlayerIdx].rank = finishedCount + 1;
      }
      return newPlayers;
    });

    setTimeout(() => {
        setPlayers(currentPlayers => {
            const finishedCount = currentPlayers.filter(p => p.rank).length;
            if (finishedCount === 3) {
                const loserIdx = currentPlayers.findIndex(p => !p.rank);
                if (loserIdx !== -1) {
                    const finalPlayers = [...currentPlayers];
                    finalPlayers[loserIdx].rank = 4;
                    setIsGameOver(true);
                    return finalPlayers;
                }
            }
            return currentPlayers;
        });
        if (!isGameOver) nextTurn();
    }, 500);
  }, [currentPlayer, diceValue, nextTurn, isGameOver, players]);

  useEffect(() => {
    if (isGameOver || currentPlayer.rank) return;
    const timer = setTimeout(() => {
       if (!hasRolled && !isRolling && !isMovingPawn) {
          handleRoll();
       } else if (hasRolled && !isRolling && !isMovingPawn) {
          if (validMovePawns.length > 0) {
             animateMoveSequence(validMovePawns[0]);
          } else {
             nextTurn();
          }
       }
    }, TURN_DURATION);
    return () => clearTimeout(timer);
  }, [turnTimerKey, hasRolled, isRolling, validMovePawns, handleRoll, animateMoveSequence, nextTurn, isGameOver, isMovingPawn, diyActive, currentPlayer]);

  useEffect(() => {
    if (currentPlayer.isBot && !isGameOver && !currentPlayer.rank) {
      if (!isRolling && !hasRolled && !isMovingPawn) {
        setTimeout(handleRoll, 1000);
      } else if (hasRolled && !isRolling && !isMovingPawn) {
        setTimeout(() => {
          if (validMovePawns.length > 0) {
            const basePawn = validMovePawns.find(id => {
                const p = currentPlayer.pawns.find(p => p.id === id);
                return p?.location === -1;
            });
            const moveId = basePawn || validMovePawns[Math.floor(Math.random() * validMovePawns.length)];
            animateMoveSequence(moveId);
          }
        }, 1000);
      }
    }
  }, [currentPlayer, isRolling, hasRolled, validMovePawns, handleRoll, animateMoveSequence, isGameOver, isMovingPawn, diyActive]);

  return (
    <div className="fixed inset-0 z-50 flex flex-col bg-ludo-dark overflow-hidden">
       {/* Top Bar Header */}
       <div className="flex-none p-3 md:p-4 flex justify-between items-center z-40 bg-ludo-dark/80 backdrop-blur-sm border-b border-white/10">
          <div className="flex items-center gap-2">
             <div className="font-black text-lg md:text-xl tracking-tighter text-white uppercase">Homiies<span className="text-ludo-red">.</span></div>
          </div>
          <div className="flex items-center gap-2 md:gap-4">
            {diyUnlocked && (
              <button 
                onClick={() => setDiyActive(!diyActive)}
                className={clsx(
                  "px-2 md:px-3 py-1 border transition-all flex items-center gap-2 font-mono text-[9px] md:text-[10px] font-black",
                  diyActive ? "bg-ludo-red text-white border-ludo-red animate-pulse" : "bg-transparent text-white/30 border-white/10"
                )}
              >
                <Wand2 size={12} />
                <span className="hidden xs:inline">DIY: {diyActive ? 'ON' : 'OFF'}</span>
              </button>
            )}
            <SharpButton variant="secondary" className="px-3 md:px-4 h-7 md:h-8 text-[9px] md:text-[10px]" onClick={onExit} icon={<X size={12} />}>
              Exit
            </SharpButton>
          </div>
       </div>

       {/* Main Content Area */}
       <div className="flex-1 relative flex flex-col items-center justify-center p-4 md:p-8 overflow-y-auto overflow-x-hidden gap-8">

          <AnimatePresence>
            {pawnCelebration && (
              <motion.div 
                initial={{ opacity: 0, scale: 0.5, y: 20 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                exit={{ opacity: 0, scale: 1.5 }}
                className="absolute z-[100] pointer-events-none flex flex-col items-center justify-center bg-black/60 backdrop-blur-sm p-8 rounded-full border border-white/20 shadow-2xl"
              >
                 <Sparkles className="text-ludo-yellow w-12 h-12 mb-2 animate-bounce" />
                 <div className="font-black text-white text-2xl uppercase tracking-tighter italic">PAWN HOME!</div>
                 <div className={clsx("w-16 h-1 mt-2", pawnCelebration.color === 'red' ? 'bg-ludo-red' : pawnCelebration.color === 'blue' ? 'bg-ludo-blue' : pawnCelebration.color === 'green' ? 'bg-ludo-green' : 'bg-ludo-yellow')} />
              </motion.div>
            )}
          </AnimatePresence>

          <AnimatePresence>
            {isGameOver && (
               <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="absolute inset-0 z-[60] flex flex-col items-center justify-center bg-black/95 p-6 overflow-y-auto">
                  <Trophy size={48} className="text-ludo-yellow mb-4" />
                  <h2 className="text-3xl md:text-4xl font-black text-white mb-6 md:mb-8 italic uppercase tracking-tighter">Match Ended</h2>
                  <div className="w-full max-w-sm space-y-2">
                    {players.slice().sort((a, b) => (a.rank || 99) - (b.rank || 99)).map((p) => (
                        <div key={p.id} className={clsx("flex items-center p-3 border border-white/10 gap-4 rounded-xl", p.rank === 1 ? "bg-ludo-yellow/10" : "bg-white/5")}>
                           <div className="font-black text-xl w-6 text-white/50">{p.rank}</div>
                           <div className="w-10 h-10 border border-white/20 rounded-lg overflow-hidden"><img src={p.avatarUrl} className="w-full h-full" /></div>
                           <div className="flex-1 font-bold text-white text-sm uppercase tracking-wider">{p.name}</div>
                           <div>{p.rank === 1 && <Crown size={16} className="text-ludo-yellow fill-ludo-yellow" />}</div>
                        </div>
                    ))}
                  </div>
                  <SharpButton onClick={onExit} className="mt-8 w-full max-w-xs">Return to Lobby</SharpButton>
               </motion.div>
            )}
          </AnimatePresence>

          <AnimatePresence>{showDiyPopup && <DIYControl onSelect={handleDiySelect} />}</AnimatePresence>

          {/* Top Row Players (Red, Blue) */}
          <div className="flex justify-between w-full max-w-[700px] gap-8">
             <PlayerCard 
               player={players[0]} // Red
               active={turnIndex === 0} 
               timerKey={turnTimerKey} 
               diceValue={diceValue} 
               isRolling={isRolling} 
               hasRolled={hasRolled} 
               onRoll={handleRoll} 
               diceSide="right"
             />
             <PlayerCard 
               player={players[1]} // Blue
               active={turnIndex === 1} 
               timerKey={turnTimerKey} 
               diceValue={diceValue} 
               isRolling={isRolling} 
               hasRolled={hasRolled} 
               onRoll={handleRoll} 
               diceSide="left"
             />
          </div>

          {/* Center Ludo Board */}
          <div className="flex-shrink-0 w-full max-w-[320px] xs:max-w-[400px] md:max-w-[550px] aspect-square relative z-10">
             <LudoBoard 
               players={players} 
               currentTurn={currentPlayer.color} 
               onPawnClick={handlePawnClick} 
               validMovePawns={validMovePawns} 
               onUnlockSecret={() => setDiyUnlocked(true)} 
             />
          </div>

          {/* Bottom Row Players (Green, Yellow) */}
          <div className="flex justify-between w-full max-w-[700px] gap-8">
             <PlayerCard 
               player={players[3]} // Green
               active={turnIndex === 3} 
               timerKey={turnTimerKey} 
               diceValue={diceValue} 
               isRolling={isRolling} 
               hasRolled={hasRolled} 
               onRoll={handleRoll} 
               diceSide="right"
             />
             <PlayerCard 
               player={players[2]} // Yellow
               active={turnIndex === 2} 
               timerKey={turnTimerKey} 
               diceValue={diceValue} 
               isRolling={isRolling} 
               hasRolled={hasRolled} 
               onRoll={handleRoll} 
               diceSide="left"
             />
          </div>
       </div>
    </div>
  );
};

interface PlayerCardProps {
   player: PlayerState;
   active: boolean;
   timerKey: number;
   diceValue: number;
   isRolling: boolean;
   hasRolled: boolean;
   onRoll: () => void;
   diceSide: 'left' | 'right';
}

const PlayerCard: React.FC<PlayerCardProps> = ({ player, active, timerKey, diceValue, isRolling, hasRolled, onRoll, diceSide }) => {
  const colorStyles = { red: 'border-ludo-red', green: 'border-ludo-green', blue: 'border-ludo-blue', yellow: 'border-ludo-yellow' };
  const bgStyles = { red: 'bg-ludo-red', green: 'bg-ludo-green', blue: 'bg-ludo-blue', yellow: 'bg-ludo-yellow' };
  const diceColors = { red: '#FF4757', green: '#2ED573', blue: '#1E90FF', yellow: '#FFA502' };

  return (
    <div className={clsx(
      "flex items-center gap-3 transition-all duration-300",
      diceSide === 'right' ? 'flex-row' : 'flex-row-reverse'
    )}>
       <div className={clsx(
          "relative min-w-[120px] md:min-w-[150px] transition-all duration-300 flex items-center bg-white/5 border-2 rounded-2xl overflow-hidden p-2 gap-3",
          active ? `${colorStyles[player.color]} scale-105 z-30 shadow-[0_0_25px_rgba(0,0,0,0.6)]` : "border-white/5 grayscale opacity-40",
       )}>
          <div className="relative w-10 h-10 md:w-12 md:h-12 border border-white/20 rounded-xl overflow-hidden flex-shrink-0">
             <img src={player.avatarUrl} className="w-full h-full object-cover" alt={player.name} />
          </div>
          <div className="flex-1 overflow-hidden">
             <div className="font-black truncate uppercase tracking-tighter text-[10px] md:text-xs leading-none italic text-white">{player.name}</div>
             <div className="flex gap-1 mt-1 opacity-50">
                <div className="text-[7px] md:text-[8px] bg-white/10 px-1 rounded font-mono uppercase">H:{player.pawns.filter(p=>p.location===-1).length}</div>
                <div className="text-[7px] md:text-[8px] bg-white/10 px-1 rounded font-mono uppercase">W:{player.pawns.filter(p=>p.location===99).length}</div>
             </div>
          </div>

          {player.rank && (
             <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
                <span className="text-ludo-yellow font-black text-base md:text-xl italic">{player.rank}#</span>
             </div>
          )}
       </div>

       <AnimatePresence>
          {active && !player.rank && (
             <motion.div 
               initial={{ opacity: 0, scale: 0.8, x: diceSide === 'right' ? -20 : 20 }}
               animate={{ opacity: 1, scale: 1, x: 0 }}
               exit={{ opacity: 0, scale: 0.8, x: diceSide === 'right' ? -20 : 20 }}
               className="flex flex-col items-center gap-1"
             >
                <Dice value={diceValue} rolling={isRolling} onRoll={handleRoll} disabled={player.isBot || hasRolled} color={diceColors[player.color]} className="w-12 h-12 md:w-16 md:h-16" />
                <div className="w-full h-1 bg-white/5 overflow-hidden rounded-full">
                   <motion.div 
                     key={timerKey} 
                     className={clsx("h-full", bgStyles[player.color])} 
                     initial={{ width: "100%" }} 
                     animate={{ width: "0%" }} 
                     transition={{ duration: TURN_DURATION / 1000, ease: "linear" }} 
                   />
                </div>
             </motion.div>
          )}
       </AnimatePresence>
    </div>
  );
};

import React, { useRef } from 'react';
import { clsx } from 'clsx';
import { Star, ArrowRight, ArrowDown, ArrowLeft, ArrowUp } from 'lucide-react';
import { PlayerState, PlayerColor } from '../../types';
import { Pawn } from './Pawn';
import { getPawnCoordinates } from './gameUtils';
import { motion } from 'framer-motion';

interface LudoBoardProps {
  players?: PlayerState[];
  currentTurn?: PlayerColor;
  onPawnClick?: (playerId: string, pawnId: string) => void;
  validMovePawns?: string[];
  onUnlockSecret?: () => void;
}

export const LudoBoard: React.FC<LudoBoardProps> = ({ 
  players = [], 
  currentTurn, 
  onPawnClick,
  validMovePawns = [],
  onUnlockSecret
}) => {
  const secretClickCount = useRef(0);
  const secretClickTimeout = useRef<any>(null);

  const handleSecretClick = () => {
    secretClickCount.current += 1;
    if (secretClickTimeout.current) clearTimeout(secretClickTimeout.current);
    secretClickTimeout.current = setTimeout(() => { secretClickCount.current = 0; }, 1000);
    if (secretClickCount.current >= 7) {
        if (onUnlockSecret) onUnlockSecret();
        secretClickCount.current = 0;
    }
  };

  const pawnsByCell: Record<string, { pawn: any, player: PlayerState }[]> = {};
  players.forEach(player => {
    player.pawns.forEach(pawn => {
      if (pawn.location !== -1) {
        const [x, y] = getPawnCoordinates(player.color, pawn.location, pawn.id);
        const key = `${x}-${y}`;
        if (!pawnsByCell[key]) pawnsByCell[key] = [];
        pawnsByCell[key].push({ pawn, player });
      }
    });
  });

  const getCellContent = (x: number, y: number) => {
    const key = `${x}-${y}`;
    const cellPawns = pawnsByCell[key] || [];
    if (cellPawns.length === 0) return null;
    return (
      <div className={clsx("absolute inset-0 flex items-center justify-center pointer-events-none z-10", cellPawns.length > 1 ? "grid grid-cols-2 p-0.5 gap-0.5" : "p-1")}>
        {cellPawns.map(({ pawn, player }) => (
           <div key={pawn.id} className="pointer-events-auto flex items-center justify-center w-full h-full">
             <Pawn color={player.color} id={pawn.id} isClickable={validMovePawns.includes(pawn.id) && player.color === currentTurn} onClick={() => onPawnClick && onPawnClick(player.id, pawn.id)} pulse={validMovePawns.includes(pawn.id)} size={pawn.location === 99 ? 'small' : 'normal'} />
           </div>
        ))}
      </div>
    );
  };

  const getCellData = (x: number, y: number) => {
    if (x < 6 && y < 6) return { type: 'BASE', color: 'red', id: 'base-red' };
    if (x > 8 && y < 6) return { type: 'BASE', color: 'blue', id: 'base-blue' }; 
    if (x < 6 && y > 8) return { type: 'BASE', color: 'green', id: 'base-green' }; 
    if (x > 8 && y > 8) return { type: 'BASE', color: 'yellow', id: 'base-yellow' };
    if (x >= 6 && x <= 8 && y >= 6 && y <= 8) return { type: 'CENTER' };
    if (y >= 6 && y <= 8 && x < 6) {
      if (y === 7 && x > 0) return { type: 'PATH_HOME', color: 'red' };
      if (y === 6 && x === 1) return { type: 'START', color: 'red' };
      if (y === 8 && x === 2) return { type: 'SAFE' };
      return { type: 'PATH' };
    }
    if (y >= 6 && y <= 8 && x > 8) {
      if (y === 7 && x < 14) return { type: 'PATH_HOME', color: 'yellow' };
      if (y === 8 && x === 13) return { type: 'START', color: 'yellow' };
      if (y === 6 && x === 12) return { type: 'SAFE' };
      return { type: 'PATH' };
    }
    if (x >= 6 && x <= 8 && y < 6) {
      if (x === 7 && y > 0) return { type: 'PATH_HOME', color: 'blue' }; 
      if (x === 8 && y === 1) return { type: 'START', color: 'blue' }; 
      if (x === 6 && y === 2) return { type: 'SAFE' };
      return { type: 'PATH' };
    }
    if (x >= 6 && x <= 8 && y > 8) {
      if (x === 7 && y < 14) return { type: 'PATH_HOME', color: 'green' }; 
      if (x === 6 && y === 13) return { type: 'START', color: 'green' }; 
      if (x === 8 && y === 12) return { type: 'SAFE' };
      return { type: 'PATH' };
    }
    return { type: 'EMPTY' };
  };

  const renderCells = () => {
    const cells = [];
    const renderedBases = new Set();
    for (let y = 0; y < 15; y++) {
      for (let x = 0; x < 15; x++) {
        const data = getCellData(x, y);
        const key = `${x}-${y}`;
        if (data.type === 'BASE') {
          if (!renderedBases.has(data.id)) {
            renderedBases.add(data.id);
            const basePlayer = players.find(p => p.color === data.color);
            cells.push(
              <div key={key} className={clsx("col-span-6 row-span-6 border-[6px] border-ludo-dark relative z-0 rounded-[2.5rem] shadow-inner transition-transform duration-500", data.color === 'red' ? 'bg-ludo-red' : data.color === 'green' ? 'bg-ludo-green' : data.color === 'blue' ? 'bg-ludo-blue' : 'bg-ludo-yellow')}>
                <div className="absolute inset-4 bg-white/90 shadow-[inset_0_4px_12px_rgba(0,0,0,0.1)] grid grid-cols-2 grid-rows-2 gap-4 p-5 rounded-[2rem]">
                  {[0, 1, 2, 3].map((slotIdx) => {
                    const pawn = basePlayer?.pawns[slotIdx];
                    const isInBase = pawn?.location === -1;
                    return (
                      <div key={slotIdx} className={clsx("flex items-center justify-center relative rounded-full border border-black/5", data.color === 'red' ? 'bg-ludo-red/10' : data.color === 'green' ? 'bg-ludo-green/10' : data.color === 'blue' ? 'bg-ludo-blue/10' : 'bg-ludo-yellow/10')}>
                        <div className="w-1/2 h-1/2 bg-white/40 rounded-full blur-[2px]" />
                        {pawn && isInBase && (
                          <div className="absolute inset-0 flex items-center justify-center pointer-events-auto z-20">
                             <Pawn color={data.color as PlayerColor} id={pawn.id} isClickable={isInBase && validMovePawns.includes(pawn.id) && data.color === currentTurn} onClick={() => onPawnClick && onPawnClick(basePlayer.id, pawn.id)} pulse={isInBase && validMovePawns.includes(pawn.id)} />
                          </div>
                        )}
                      </div>
                    )
                  })}
                </div>
              </div>
            );
          }
          continue;
        }
        if (data.type === 'CENTER') {
           if (x === 6 && y === 6) {
             cells.push(
               <div key={key} onClick={handleSecretClick} className="col-span-3 row-span-3 bg-ludo-dark relative border-[6px] border-ludo-dark active:scale-[0.98] transition-transform shadow-2xl">
                  <div className="absolute inset-0 bg-ludo-red" style={{ clipPath: 'polygon(0 0, 0 100%, 50% 50%)' }}></div>
                  <div className="absolute inset-0 bg-ludo-blue" style={{ clipPath: 'polygon(0 0, 100% 0, 50% 50%)' }}></div>
                  <div className="absolute inset-0 bg-ludo-yellow" style={{ clipPath: 'polygon(100% 0, 100% 100%, 50% 50%)' }}></div>
                  <div className="absolute inset-0 bg-ludo-green" style={{ clipPath: 'polygon(0 100%, 100% 100%, 50% 50%)' }}></div>
                  <div className="absolute inset-[20%] border border-white/20 rounded-full animate-spin-slow"></div>
               </div>
             )
           }
           continue;
        }
        let bgClass = "bg-white";
        let content = null;
        if (data.type === 'PATH_HOME') bgClass = data.color === 'red' ? 'bg-ludo-red' : data.color === 'green' ? 'bg-ludo-green' : data.color === 'blue' ? 'bg-ludo-blue' : 'bg-ludo-yellow';
        if (data.type === 'START') {
           bgClass = data.color === 'red' ? 'bg-ludo-red' : data.color === 'green' ? 'bg-ludo-green' : data.color === 'blue' ? 'bg-ludo-blue' : 'bg-ludo-yellow';
           if (data.color === 'red') content = <ArrowRight className="text-white opacity-60" size={14} />;
           if (data.color === 'blue') content = <ArrowDown className="text-white opacity-60" size={14} />; 
           if (data.color === 'yellow') content = <ArrowLeft className="text-white opacity-60" size={14} />;
           if (data.color === 'green') content = <ArrowUp className="text-white opacity-60" size={14} />; 
        }
        if (data.type === 'SAFE') {
           content = <motion.div animate={{ opacity: [0.4, 0.8, 0.4] }} transition={{ repeat: Infinity, duration: 2 }}><Star className="text-ludo-dark/20 fill-ludo-dark/10" size={16} /></motion.div>;
           bgClass = "bg-gray-100";
        }
        cells.push(
          <div key={key} className={clsx("relative flex items-center justify-center w-full h-full border-[0.5px] border-ludo-dark/10 transition-colors duration-300", bgClass)}>
            {content}
            {getCellContent(x, y)}
            {data.type === 'PATH_HOME' && <div className="absolute inset-0 bg-white/10" />}
          </div>
        );
      }
    }
    return cells;
  };

  return (
    <div className="aspect-square w-full h-full max-w-[650px] bg-ludo-dark p-4 shadow-[0_32px_64px_-12px_rgba(0,0,0,0.8)] relative select-none rounded-[4rem]">
      <div className="grid grid-cols-15 grid-rows-15 w-full h-full bg-white border-4 border-ludo-dark rounded-[3rem] overflow-hidden shadow-2xl">
        {renderCells()}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { clsx } from 'clsx';
import { LudoBoard } from './LudoBoard';
import { Dice } from './Dice';
import { DIYControl } from './DIYControl';
import { SharpButton } from '../ui/SharpButton';
import { PlayerState, PlayerColor } from '../../types';
import { isValidMove, SAFE_INDICES, PLAYER_START_OFFSETS } from './gameUtils';
import { X, Trophy, Wand2, Crown, Star, Sparkles } from 'lucide-react';

interface GameScreenProps {
  onExit: () => void;
  vsComputer?: boolean;
}

const TURN_DURATION = 15000; // 15 seconds
const MOVE_STEP_DELAY = 180; // Snappier movement

export const GameScreen: React.FC<GameScreenProps> = ({ onExit, vsComputer = false }) => {
  // --- Game State ---
  const [players, setPlayers] = useState<PlayerState[]>([
    { 
      id: 'p1', name: 'You', color: 'red', avatarUrl: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Felix', 
      isBot: false, 
      pawns: [0,1,2,3].map(i => ({ id: `red-${i}`, color: 'red', location: -1 })) 
    },
    { 
      id: 'p2', name: vsComputer ? 'Bot Blue' : 'Player 2', color: 'blue', avatarUrl: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Sarah', 
      isBot: vsComputer, 
      pawns: [0,1,2,3].map(i => ({ id: `blue-${i}`, color: 'blue', location: -1 })) 
    },
    { 
      id: 'p3', name: vsComputer ? 'Bot Yellow' : 'Player 3', color: 'yellow', avatarUrl: 'https://api.dicebear.com/7.x/avataaars/svg?seed=John', 
      isBot: vsComputer, 
      pawns: [0,1,2,3].map(i => ({ id: `yellow-${i}`, color: 'yellow', location: -1 })) 
    },
    { 
      id: 'p4', name: vsComputer ? 'Bot Green' : 'Player 4', color: 'green', avatarUrl: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Aneka', 
      isBot: vsComputer, 
      pawns: [0,1,2,3].map(i => ({ id: `green-${i}`, color: 'green', location: -1 })) 
    },
  ]);

  const [turnIndex, setTurnIndex] = useState(0);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [hasRolled, setHasRolled] = useState(false);
  const [validMovePawns, setValidMovePawns] = useState<string[]>([]);

  // Game Status
  const [isGameOver, setIsGameOver] = useState(false);
  const [turnTimerKey, setTurnTimerKey] = useState(0);
  const [isMovingPawn, setIsMovingPawn] = useState(false);
  const [pawnCelebration, setPawnCelebration] = useState<{ color: PlayerColor, pawnId: string } | null>(null);

  // --- Secret DIY State ---
  const [diyUnlocked, setDiyUnlocked] = useState(false);
  const [diyActive, setDiyActive] = useState(false);
  const [showDiyPopup, setShowDiyPopup] = useState(false);
  const diySelectedRef = useRef<number | null>(null);

  const currentPlayer = players[turnIndex];

  // Helper to get number of finished players
  const getFinishedCount = useCallback(() => {
    return players.filter(p => p.rank).length;
  }, [players]);

  // --- Core Game Logic ---
  const nextTurn = useCallback(() => {
    if (getFinishedCount() >= 3) {
      setIsGameOver(true);
      return;
    }

    setHasRolled(false);
    setValidMovePawns([]);
    setTurnTimerKey(prev => prev + 1);
    setIsMovingPawn(false);

    setTurnIndex(prevIndex => {
      let nextIndex = (prevIndex + 1) % 4;
      let loopCount = 0;

      while (players[nextIndex].rank && loopCount < 4) {
        nextIndex = (nextIndex + 1) % 4;
        loopCount++;
      }

      if (loopCount >= 4) return prevIndex;
      if (diceValue === 6 && !players[prevIndex].rank) {
         return prevIndex;
      }
      return nextIndex;
    });
  }, [diceValue, players, getFinishedCount]);

  const handleRoll = useCallback(() => {
    if (isRolling || hasRolled || isGameOver || isMovingPawn || currentPlayer.rank) return;
    setIsRolling(true);
    if (diyActive) {
      setShowDiyPopup(true);
      diySelectedRef.current = null;
    }
    const rollDuration = diyActive ? 1200 : 600; 
    setTimeout(() => {
      let rolledValue = Math.floor(Math.random() * 6) + 1;
      if (diyActive) {
        setShowDiyPopup(false);
        if (diySelectedRef.current !== null) {
          rolledValue = diySelectedRef.current;
        }
      }
      setDiceValue(rolledValue);
      setIsRolling(false);
      setHasRolled(true);
      const moves: string[] = [];
      currentPlayer.pawns.forEach(pawn => {
        if (isValidMove(pawn.location, rolledValue)) {
          moves.push(pawn.id);
        }
      });
      setValidMovePawns(moves);
      if (moves.length === 0) {
        setTimeout(nextTurn, 1000);
      }
    }, rollDuration);
  }, [currentPlayer, isRolling, hasRolled, isGameOver, isMovingPawn, nextTurn, diyActive]);

  const handleDiySelect = (value: number) => {
    diySelectedRef.current = value;
  };

  const handlePawnClick = (playerId: string, pawnId: string) => {
    if (!hasRolled || playerId !== currentPlayer.id || !validMovePawns.includes(pawnId) || isMovingPawn) return;
    animateMoveSequence(pawnId);
  };

  const setPawnLocation = (pawnId: string, newLoc: number) => {
    setPlayers(prevPlayers => {
      return prevPlayers.map(player => {
        if (player.id !== currentPlayer.id) return player;
        return {
          ...player,
          pawns: player.pawns.map(pawn => 
            pawn.id === pawnId ? { ...pawn, location: newLoc } : pawn
          )
        };
      });
    });
  };

  const animateMoveSequence = useCallback(async (pawnId: string) => {
    setIsMovingPawn(true);
    const player = players.find(p => p.id === currentPlayer.id);
    const pawn = player?.pawns.find(p => p.id === pawnId);
    if (!player || !pawn) return;

    const currentLoc = pawn.location;
    const stepsToMove = (currentLoc === -1) ? 1 : diceValue;

    for (let i = 1; i <= stepsToMove; i++) {
        let nextLoc = (currentLoc === -1) ? 0 : (currentLoc + i);

        // Handle Home Logic (57 = 99)
        if (nextLoc >= 57) {
          nextLoc = 99;
          setPawnLocation(pawnId, nextLoc);
          break; // Reach home immediately if it exceeds path
        }

        setPawnLocation(pawnId, nextLoc);
        await new Promise(resolve => setTimeout(resolve, MOVE_STEP_DELAY));
    }

    // Final calculations after all steps are processed
    let finalLocation = (currentLoc === -1) ? 0 : (currentLoc + diceValue);
    if (finalLocation >= 57) finalLocation = 99;

    setPlayers(prev => {
      const newPlayers = [...prev];
      const currentPlayerIdx = newPlayers.findIndex(p => p.id === player.id);

      // Capture Logic
      if (finalLocation < 51) { 
        const offset = PLAYER_START_OFFSETS[player.color];
        const globalPos = (offset + finalLocation) % 52;
        const isSafe = SAFE_INDICES.includes(globalPos);

        if (!isSafe) {
           newPlayers.forEach((opp, oppIdx) => {
              if (opp.id !== player.id && !opp.rank) {
                  opp.pawns.forEach((oppPawn, oppPawnIdx) => {
                      const oppOffset = PLAYER_START_OFFSETS[opp.color];
                      const oppGlobal = oppPawn.location !== -1 && oppPawn.location < 51 
                          ? (oppOffset + oppPawn.location) % 52 
                          : -999;

                      if (globalPos === oppGlobal) {
                          newPlayers[oppIdx].pawns[oppPawnIdx].location = -1;
                      }
                  });
              }
           });
        }
      }

      // Check if pawn just reached home
      if (finalLocation === 99) {
         setPawnCelebration({ color: player.color, pawnId: pawnId });
         setTimeout(() => setPawnCelebration(null), 2500);
      }

      // Win Condition
      const hasWonNow = newPlayers[currentPlayerIdx].pawns.every(p => p.location === 99);
      if (hasWonNow && !newPlayers[currentPlayerIdx].rank) {
         const finishedCount = newPlayers.filter(p => p.rank).length;
         newPlayers[currentPlayerIdx].rank = finishedCount + 1;
      }
      return newPlayers;
    });

    setTimeout(() => {
        setPlayers(currentPlayers => {
            const finishedCount = currentPlayers.filter(p => p.rank).length;
            if (finishedCount === 3) {
                const loserIdx = currentPlayers.findIndex(p => !p.rank);
                if (loserIdx !== -1) {
                    const finalPlayers = [...currentPlayers];
                    finalPlayers[loserIdx].rank = 4;
                    setIsGameOver(true);
                    return finalPlayers;
                }
            }
            return currentPlayers;
        });
        if (!isGameOver) nextTurn();
    }, 500);
  }, [currentPlayer, diceValue, nextTurn, isGameOver, players]);

  useEffect(() => {
    if (isGameOver || currentPlayer.rank) return;
    const timer = setTimeout(() => {
       if (!hasRolled && !isRolling && !isMovingPawn) {
          handleRoll();
       } else if (hasRolled && !isRolling && !isMovingPawn) {
          if (validMovePawns.length > 0) {
             animateMoveSequence(validMovePawns[0]);
          } else {
             nextTurn();
          }
       }
    }, TURN_DURATION);
    return () => clearTimeout(timer);
  }, [turnTimerKey, hasRolled, isRolling, validMovePawns, handleRoll, animateMoveSequence, nextTurn, isGameOver, isMovingPawn, diyActive, currentPlayer]);

  useEffect(() => {
    if (currentPlayer.isBot && !isGameOver && !currentPlayer.rank) {
      if (!isRolling && !hasRolled && !isMovingPawn) {
        setTimeout(handleRoll, 1000);
      } else if (hasRolled && !isRolling && !isMovingPawn) {
        setTimeout(() => {
          if (validMovePawns.length > 0) {
            const basePawn = validMovePawns.find(id => {
                const p = currentPlayer.pawns.find(p => p.id === id);
                return p?.location === -1;
            });
            const moveId = basePawn || validMovePawns[Math.floor(Math.random() * validMovePawns.length)];
            animateMoveSequence(moveId);
          }
        }, 1000);
      }
    }
  }, [currentPlayer, isRolling, hasRolled, validMovePawns, handleRoll, animateMoveSequence, isGameOver, isMovingPawn, diyActive]);

  return (
    <div className="fixed inset-0 z-50 flex flex-col bg-ludo-dark overflow-hidden">
       {/* Top Bar Header */}
       <div className="flex-none p-3 md:p-4 flex justify-between items-center z-40 bg-ludo-dark/80 backdrop-blur-sm border-b border-white/10">
          <div className="flex items-center gap-2">
             <div className="font-black text-lg md:text-xl tracking-tighter text-white uppercase">Homiies<span className="text-ludo-red">.</span></div>
          </div>
          <div className="flex items-center gap-2 md:gap-4">
            {diyUnlocked && (
              <button 
                onClick={() => setDiyActive(!diyActive)}
                className={clsx(
                  "px-2 md:px-3 py-1 border transition-all flex items-center gap-2 font-mono text-[9px] md:text-[10px] font-black",
                  diyActive ? "bg-ludo-red text-white border-ludo-red animate-pulse" : "bg-transparent text-white/30 border-white/10"
                )}
              >
                <Wand2 size={12} />
                <span className="hidden xs:inline">DIY: {diyActive ? 'ON' : 'OFF'}</span>
              </button>
            )}
            <SharpButton variant="secondary" className="px-3 md:px-4 h-7 md:h-8 text-[9px] md:text-[10px]" onClick={onExit} icon={<X size={12} />}>
              Exit
            </SharpButton>
          </div>
       </div>

       {/* Main Content Area */}
       <div className="flex-1 relative flex flex-col items-center justify-center p-4 md:p-8 overflow-y-auto overflow-x-hidden gap-8">

          <AnimatePresence>
            {pawnCelebration && (
              <motion.div 
                initial={{ opacity: 0, scale: 0.5, y: 20 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                exit={{ opacity: 0, scale: 1.5 }}
                className="absolute z-[100] pointer-events-none flex flex-col items-center justify-center bg-black/60 backdrop-blur-sm p-8 rounded-full border border-white/20 shadow-2xl"
              >
                 <Sparkles className="text-ludo-yellow w-12 h-12 mb-2 animate-bounce" />
                 <div className="font-black text-white text-2xl uppercase tracking-tighter italic">PAWN HOME!</div>
                 <div className={clsx("w-16 h-1 mt-2", pawnCelebration.color === 'red' ? 'bg-ludo-red' : pawnCelebration.color === 'blue' ? 'bg-ludo-blue' : pawnCelebration.color === 'green' ? 'bg-ludo-green' : 'bg-ludo-yellow')} />
              </motion.div>
            )}
          </AnimatePresence>

          <AnimatePresence>
            {isGameOver && (
               <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="absolute inset-0 z-[60] flex flex-col items-center justify-center bg-black/95 p-6 overflow-y-auto">
                  <Trophy size={48} className="text-ludo-yellow mb-4" />
                  <h2 className="text-3xl md:text-4xl font-black text-white mb-6 md:mb-8 italic uppercase tracking-tighter">Match Ended</h2>
                  <div className="w-full max-w-sm space-y-2">
                    {players.slice().sort((a, b) => (a.rank || 99) - (b.rank || 99)).map((p) => (
                        <div key={p.id} className={clsx("flex items-center p-3 border border-white/10 gap-4 rounded-xl", p.rank === 1 ? "bg-ludo-yellow/10" : "bg-white/5")}>
                           <div className="font-black text-xl w-6 text-white/50">{p.rank}</div>
                           <div className="w-10 h-10 border border-white/20 rounded-lg overflow-hidden"><img src={p.avatarUrl} className="w-full h-full" /></div>
                           <div className="flex-1 font-bold text-white text-sm uppercase tracking-wider">{p.name}</div>
                           <div>{p.rank === 1 && <Crown size={16} className="text-ludo-yellow fill-ludo-yellow" />}</div>
                        </div>
                    ))}
                  </div>
                  <SharpButton onClick={onExit} className="mt-8 w-full max-w-xs">Return to Lobby</SharpButton>
               </motion.div>
            )}
          </AnimatePresence>

          <AnimatePresence>{showDiyPopup && <DIYControl onSelect={handleDiySelect} />}</AnimatePresence>

          {/* Top Row Players (Red, Blue) */}
          <div className="flex justify-between w-full max-w-[700px] gap-8">
             <PlayerCard 
               player={players[0]} // Red
               active={turnIndex === 0} 
               timerKey={turnTimerKey} 
               diceValue={diceValue} 
               isRolling={isRolling} 
               hasRolled={hasRolled} 
               onRoll={handleRoll} 
               diceSide="right"
             />
             <PlayerCard 
               player={players[1]} // Blue
               active={turnIndex === 1} 
               timerKey={turnTimerKey} 
               diceValue={diceValue} 
               isRolling={isRolling} 
               hasRolled={hasRolled} 
               onRoll={handleRoll} 
               diceSide="left"
             />
          </div>

          {/* Center Ludo Board */}
          <div className="flex-shrink-0 w-full max-w-[320px] xs:max-w-[400px] md:max-w-[550px] aspect-square relative z-10">
             <LudoBoard 
               players={players} 
               currentTurn={currentPlayer.color} 
               onPawnClick={handlePawnClick} 
               validMovePawns={validMovePawns} 
               onUnlockSecret={() => setDiyUnlocked(true)} 
             />
          </div>

          {/* Bottom Row Players (Green, Yellow) */}
          <div className="flex justify-between w-full max-w-[700px] gap-8">
             <PlayerCard 
               player={players[3]} // Green
               active={turnIndex === 3} 
               timerKey={turnTimerKey} 
               diceValue={diceValue} 
               isRolling={isRolling} 
               hasRolled={hasRolled} 
               onRoll={handleRoll} 
               diceSide="right"
             />
             <PlayerCard 
               player={players[2]} // Yellow
               active={turnIndex === 2} 
               timerKey={turnTimerKey} 
               diceValue={diceValue} 
               isRolling={isRolling} 
               hasRolled={hasRolled} 
               onRoll={handleRoll} 
               diceSide="left"
             />
          </div>
       </div>
    </div>
  );
};

interface PlayerCardProps {
   player: PlayerState;
   active: boolean;
   timerKey: number;
   diceValue: number;
   isRolling: boolean;
   hasRolled: boolean;
   onRoll: () => void;
   diceSide: 'left' | 'right';
}

const PlayerCard: React.FC<PlayerCardProps> = ({ player, active, timerKey, diceValue, isRolling, hasRolled, onRoll, diceSide }) => {
  const colorStyles = { red: 'border-ludo-red', green: 'border-ludo-green', blue: 'border-ludo-blue', yellow: 'border-ludo-yellow' };
  const bgStyles = { red: 'bg-ludo-red', green: 'bg-ludo-green', blue: 'bg-ludo-blue', yellow: 'bg-ludo-yellow' };
  const diceColors = { red: '#FF4757', green: '#2ED573', blue: '#1E90FF', yellow: '#FFA502' };

  return (
    <div className={clsx(
      "flex items-center gap-3 transition-all duration-300",
      diceSide === 'right' ? 'flex-row' : 'flex-row-reverse'
    )}>
       <div className={clsx(
          "relative min-w-[120px] md:min-w-[150px] transition-all duration-300 flex items-center bg-white/5 border-2 rounded-2xl overflow-hidden p-2 gap-3",
          active ? `${colorStyles[player.color]} scale-105 z-30 shadow-[0_0_25px_rgba(0,0,0,0.6)]` : "border-white/5 grayscale opacity-40",
       )}>
          <div className="relative w-10 h-10 md:w-12 md:h-12 border border-white/20 rounded-xl overflow-hidden flex-shrink-0">
             <img src={player.avatarUrl} className="w-full h-full object-cover" alt={player.name} />
          </div>
          <div className="flex-1 overflow-hidden">
             <div className="font-black truncate uppercase tracking-tighter text-[10px] md:text-xs leading-none italic text-white">{player.name}</div>
             <div className="flex gap-1 mt-1 opacity-50">
                <div className="text-[7px] md:text-[8px] bg-white/10 px-1 rounded font-mono uppercase">H:{player.pawns.filter(p=>p.location===-1).length}</div>
                <div className="text-[7px] md:text-[8px] bg-white/10 px-1 rounded font-mono uppercase">W:{player.pawns.filter(p=>p.location===99).length}</div>
             </div>
          </div>

          {player.rank && (
             <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
                <span className="text-ludo-yellow font-black text-base md:text-xl italic">{player.rank}#</span>
             </div>
          )}
       </div>

       <AnimatePresence>
          {active && !player.rank && (
             <motion.div 
               initial={{ opacity: 0, scale: 0.8, x: diceSide === 'right' ? -20 : 20 }}
               animate={{ opacity: 1, scale: 1, x: 0 }}
               exit={{ opacity: 0, scale: 0.8, x: diceSide === 'right' ? -20 : 20 }}
               className="flex flex-col items-center gap-1"
             >
                {/* Fixed incorrect reference to handleRoll inside PlayerCard by using onRoll prop */}
                <Dice value={diceValue} rolling={isRolling} onRoll={onRoll} disabled={player.isBot || hasRolled} color={diceColors[player.color]} className="w-12 h-12 md:w-16 md:h-16" />
                <div className="w-full h-1 bg-white/5 overflow-hidden rounded-full">
                   <motion.div 
                     key={timerKey} 
                     className={clsx("h-full", bgStyles[player.color])} 
                     initial={{ width: "100%" }} 
                     animate={{ width: "0%" }} 
                     transition={{ duration: TURN_DURATION / 1000, Proxy: "linear" }} 
                   />
                </div>
             </motion.div>
          )}
       </AnimatePresence>
    </div>
  );
};

