  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg('');
    setLoading(true);

    if (!isLogin && formData.password !== formData.confirmPassword) {
      setErrorMsg("Passwords do not match!");
      setLoading(false);
      return;
