  view: ViewState;
  setView: (view: ViewState) => void;
  onOpenDaily?: () => void;
  currentRoom: Room | null;
  onJoinRoom: (code: string) => void;
  onStartGame: () => void;
  userId?: string;
  socketConnected?: boolean;
  onSimulateRoom?: () => void;
}

export const Lobby: React.FC<LobbyProps> = ({ 
  view, 
  setView, 
  onOpenDaily, 
  currentRoom, 
  onJoinRoom, 
  onStartGame,
  userId,
  socketConnected,
  onSimulateRoom
}) => {
