}

export const GameScreen: React.FC<GameScreenProps> = ({ user, onExit, vsComputer = false, participants, roomCode, socket }) => {
  const [players, setPlayers] = useState<PlayerState[]>(() => {
    const colors: PlayerColor[] = ['red', 'blue', 'yellow', 'green'];

    if (participants && participants.length > 0) {
      return colors.map((color, index) => {
        const p = participants[index];
        if (p) {
          return {
            id: p.id,
            name: p.name,
            color,
            avatarUrl: p.avatarUrl,
            isBot: false,
            pawns: [0, 1, 2, 3].map(i => ({ id: `${color}-${i}`, color, location: -1 }))
          };
        }
        return {
          id: `bot-${color}`,
          name: `Bot ${color.toUpperCase()}`,
          color,
          avatarUrl: `https://api.dicebear.com/7.x/avataaars/svg?seed=Bot${color}`,
          isBot: true,
          pawns: [0, 1, 2, 3].map(i => ({ id: `${color}-${i}`, color, location: -1 }))
        };
      });
    }

    return colors.map((color, index) => {
      if (index === 0) {
        return {
          id: user.id,
          name: user.name,
          color,
          avatarUrl: user.avatarUrl,
          isBot: false,
          pawns: [0, 1, 2, 3].map(i => ({ id: `${color}-${i}`, color, location: -1 }))
        };
      }
      return {
        id: `bot-${color}`,
        name: `Bot ${color.toUpperCase()}`,
        color,
        avatarUrl: `https://api.dicebear.com/7.x/avataaars/svg?seed=Bot${color}`,
        isBot: true,
        pawns: [0, 1, 2, 3].map(i => ({ id: `${color}-${i}`, color, location: -1 }))
      };
    });
  });

  const playersRef = useRef(players);
  useEffect(() => { playersRef.current = players; }, [players]);

  const [turnIndex, setTurnIndex] = useState(0);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [hasRolled, setHasRolled] = useState(false);
  const [validMovePawns, setValidMovePawns] = useState<string[]>([]);
  const [isGameOver, setIsGameOver] = useState(false);
  const [isMovingPawn, setIsMovingPawn] = useState(false);
  const [pawnCelebration, setPawnCelebration] = useState<{ color: PlayerColor, pawnId: string } | null>(null);

  const currentPlayer = players[turnIndex];
  const isMyTurn = currentPlayer?.id === user.id;

  const resetRollingState = useCallback(() => {
    setIsRolling(false);
    setHasRolled(false);
    setValidMovePawns([]);
    setIsMovingPawn(false);
  }, []);

  const nextTurnLocal = useCallback(() => {
    let nextIdx = (turnIndex + 1) % 4;
    let loopLimit = 0;
    while (players[nextIdx].rank && loopLimit < 4) {
      nextIdx = (nextIdx + 1) % 4;
      loopLimit++;
    }

    setTurnIndex(nextIdx);
    resetRollingState();
  }, [turnIndex, players, resetRollingState]);

  const handleNextTurn = useCallback(() => {
    if (vsComputer) {
      nextTurnLocal();
      return;
    }
    if (!socket || !roomCode || !isMyTurn) return;
    let nextIdx = (turnIndex + 1) % 4;
    while (players[nextIdx].rank) nextIdx = (nextIdx + 1) % 4;
    socket.emit('next_turn', { roomCode, nextIndex: nextIdx });
  }, [vsComputer, nextTurnLocal, socket, roomCode, isMyTurn, turnIndex, players]);

  // Socket Synchronization
  useEffect(() => {
    if (!socket || !roomCode || vsComputer) return;

    const onSyncDice = ({ value, playerIndex }: any) => {
      console.log('Dice synced:', value, 'for player', playerIndex);
      setDiceValue(value);
      setIsRolling(false); 
      setHasRolled(true);

      const currentPlayers = playersRef.current;
      const player = currentPlayers[playerIndex];
      if (!player) return;

      const moves: string[] = [];
      player.pawns.forEach(pawn => {
        if (isValidMove(pawn.location, value)) moves.push(pawn.id);
      });

      setValidMovePawns(moves);
      if (moves.length === 0 && player.id === user.id) {
        setTimeout(handleNextTurn, 1000);
      }
    };

    const onSyncMove = ({ pawnId, finalLocation, playerIndex }: any) => {
      syncMoveExternally(pawnId, finalLocation, playerIndex);
    };

    const onSyncTurn = (nextIdx: number) => {
      console.log('Turn synced to:', nextIdx);
      setTurnIndex(nextIdx);
      resetRollingState();
    };

    socket.on('sync_dice', onSyncDice);
    socket.on('sync_move', onSyncMove);
    socket.on('sync_turn', onSyncTurn);

    return () => {
      socket.off('sync_dice', onSyncDice);
      socket.off('sync_move', onSyncMove);
      socket.off('sync_turn', onSyncTurn);
    };
  }, [socket, roomCode, vsComputer, handleNextTurn, user.id, resetRollingState]);

  const handleRoll = () => {
    if (isRolling || hasRolled || isMovingPawn) return;
    if (!vsComputer && !isMyTurn) return;

    setIsRolling(true);

    // Hard limit stop for UI safety
    const safetyTimer = setTimeout(() => {
        setIsRolling(false);
    }, 2500);

    setTimeout(() => {
      const val = Math.floor(Math.random() * 6) + 1;
      if (vsComputer) {
        clearTimeout(safetyTimer);
        setDiceValue(val);
        setIsRolling(false);
        setHasRolled(true);
        const moves: string[] = [];
        currentPlayer.pawns.forEach(pawn => {
          if (isValidMove(pawn.location, val)) moves.push(pawn.id);
        });
        setValidMovePawns(moves);
        if (moves.length === 0) setTimeout(handleNextTurn, 1000);
      } else {
        socket?.emit('dice_rolled', { roomCode, value: val, playerIndex: turnIndex });
        clearTimeout(safetyTimer);
      }
    }, 800);
  };

  const syncMoveExternally = async (pawnId: string, finalLocation: number, playerIdx: number) => {
    setIsMovingPawn(true);
    const player = playersRef.current[playerIdx];
    const pawn = player?.pawns.find(p => p.id === pawnId);
    if (!pawn) {
      setIsMovingPawn(false);
      return;
    }

    setPlayers(prev => prev.map((p, idx) => {
      if (idx !== playerIdx) return p;
      return {
        ...p,
        pawns: p.pawns.map(pw => pw.id === pawnId ? { ...pw, location: finalLocation } : pw)
      };
    }));

    if (finalLocation === 99) setPawnCelebration({ color: player.color, pawnId });
    setTimeout(() => {
      setPawnCelebration(null);
      setIsMovingPawn(false);
      if (vsComputer) handleNextTurn();
    }, 1000);
  };

  const handlePawnClick = (playerId: string, pawnId: string) => {
    if (!hasRolled || isMovingPawn) return;
    if (!vsComputer && playerId !== user.id) return;
    if (!validMovePawns.includes(pawnId)) return;

    const pawn = currentPlayer.pawns.find(p => p.id === pawnId);
    if (!pawn) return;

    let finalLoc = (pawn.location === -1) ? 0 : (pawn.location + diceValue);
    if (finalLoc >= 57) finalLoc = 99;

    if (vsComputer) {
      syncMoveExternally(pawnId, finalLoc, turnIndex);
    } else {
      socket?.emit('move_pawn', { roomCode, pawnId, finalLocation: finalLoc, playerIndex: turnIndex });
    }
  };

  useEffect(() => {
    if (vsComputer && currentPlayer.isBot && !isGameOver && !isMovingPawn) {
      if (!isRolling && !hasRolled) {
        setTimeout(handleRoll, 1500);
      } else if (hasRolled) {
        setTimeout(() => {
          if (validMovePawns.length > 0) {
            const moveId = validMovePawns[Math.floor(Math.random() * validMovePawns.length)];
            handlePawnClick(currentPlayer.id, moveId);
          }
        }, 800);
      }
    }
  }, [vsComputer, currentPlayer, isRolling, hasRolled, validMovePawns, isGameOver, isMovingPawn]);

  if (players.length === 0) return null;

  return (
    <div className="fixed inset-0 z-50 flex flex-col bg-ludo-dark overflow-hidden">
       <div className="flex-none p-4 flex justify-between items-center bg-ludo-dark/80 border-b border-white/10">
          <div className="font-black text-xl tracking-tighter text-white uppercase">Homiies<span className="text-ludo-red">.</span></div>
          <SharpButton variant="secondary" onClick={onExit} icon={<X size={12} />}>Exit</SharpButton>
       </div>

       <div className="flex-1 relative flex flex-col items-center justify-center p-6 gap-8">
          <AnimatePresence>
            {pawnCelebration && (
              <motion.div initial={{ opacity: 0, scale: 0.5 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0 }} className="absolute z-[100] bg-black/60 p-8 rounded-full border border-white/20 text-center">
                 <Sparkles className="text-ludo-yellow w-12 h-12 mx-auto mb-2 animate-bounce" />
                 <div className="font-black text-white text-2xl uppercase italic">PAWN HOME!</div>
              </motion.div>
            )}
          </AnimatePresence>

          <div className="flex justify-between w-full max-w-[750px] gap-8">
             <PlayerTurnBox player={players[0]} active={turnIndex === 0} diceValue={diceValue} isRolling={isRolling} hasRolled={hasRolled} onRoll={handleRoll} diceSide="right" isUser={players[0]?.id === user.id} />
             <PlayerTurnBox player={players[1]} active={turnIndex === 1} diceValue={diceValue} isRolling={isRolling} hasRolled={hasRolled} onRoll={handleRoll} diceSide="left" isUser={players[1]?.id === user.id} />
          </div>

          <div className="flex-shrink-0 w-full max-w-[460px] aspect-square relative z-10">
             <LudoBoard players={players} currentTurn={currentPlayer?.color} onPawnClick={handlePawnClick} validMovePawns={validMovePawns} />
          </div>

          <div className="flex justify-between w-full max-w-[750px] gap-8">
             <PlayerTurnBox player={players[3]} active={turnIndex === 3} diceValue={diceValue} isRolling={isRolling} hasRolled={hasRolled} onRoll={handleRoll} diceSide="right" isUser={players[3]?.id === user.id} />
             <PlayerTurnBox player={players[2]} active={turnIndex === 2} diceValue={diceValue} isRolling={isRolling} hasRolled={hasRolled} onRoll={handleRoll} diceSide="left" isUser={players[2]?.id === user.id} />
          </div>
       </div>
    </div>
  );
};

interface PlayerTurnBoxProps {
   player: PlayerState; active: boolean; diceValue: number; isRolling: boolean; hasRolled: boolean; onRoll: () => void; diceSide: 'left' | 'right'; isUser: boolean;
}

const PlayerTurnBox: React.FC<PlayerTurnBoxProps> = ({ player, active, diceValue, isRolling, hasRolled, onRoll, diceSide, isUser }) => {
  if (!player) return null;
  const diceColors = { red: '#FF4757', green: '#2ED573', blue: '#1E90FF', yellow: '#FFA502' };
  return (
    <div className={clsx("flex items-center gap-2", diceSide === 'right' ? 'flex-row' : 'flex-row-reverse')}>
       <div className={clsx("relative flex items-center bg-white/5 rounded-lg p-1 gap-2 w-[100px] h-[40px]", active ? "scale-105 shadow-xl opacity-100 ring-1 ring-white/20" : "grayscale opacity-30")}>
          <div className="w-6 h-6 border border-white/10 rounded overflow-hidden">
             <img src={player.avatarUrl} className="w-full h-full object-cover" />
          </div>
          <div className="flex flex-col overflow-hidden">
            <div className="font-black truncate uppercase text-[8px] text-white leading-tight">{player.name}</div>
            {isUser && <div className="text-[6px] font-bold text-ludo-yellow uppercase">You</div>}
          </div>
       </div>
       <div className={clsx("w-10 h-10 bg-white/5 border border-white/5 rounded-lg flex items-center justify-center transition-all", active ? "bg-white/10 border-white/20" : "opacity-10")}>
          {active && <Dice value={diceValue} rolling={isRolling} onRoll={onRoll} disabled={hasRolled || (!isUser && player.isBot === false)} color={diceColors[player.color]} className="w-full h-full" />}
       </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Background } from './components/Background';
import { Lobby } from './components/Lobby';
import { TopBar } from './components/TopBar';
import { SpinWheel } from './components/SpinWheel';
import { DailyRewardOverlay } from './components/DailyRewardOverlay';
import { WalletPage } from './components/WalletPage';
import { GameScreen } from './components/Game/GameScreen';
import { ProfileOverlay } from './components/ProfileOverlay';
import { AuthPage } from './components/AuthPage';
import { TournamentPage } from './components/TournamentPage';
import { ViewState, User, UserStats, Room, RoomParticipant } from './types';
import { motion, AnimatePresence } from 'framer-motion';
import { supabase } from './lib/supabase';
import { io, Socket } from 'socket.io-client';

const DEFAULT_STATS: UserStats = {
  gamesWon: 0,
  gamesLost: 0,
  winStreak: 0,
  tokensCaptured: 0,
  tournamentsWon: 0
};

// Robust socket URL detection - defaults to port 3000 on the current host
const SOCKET_URL = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
  ? 'http://localhost:3000' 
  : `${window.location.protocol}//${window.location.hostname}:3000`;

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>(ViewState.AUTH);
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const [isSpinWheelOpen, setIsSpinWheelOpen] = useState(false);
  const [isDailyRewardOpen, setIsDailyRewardOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [gameMode, setGameMode] = useState<'FRIEND' | 'COMPUTER'>('FRIEND');

  // Room State
  const [currentRoom, setCurrentRoom] = useState<Room | null>(null);
  const [socketConnected, setSocketConnected] = useState(false);
  const socketRef = useRef<Socket | null>(null);

  // Initialize Socket only when user is available
  useEffect(() => {
    if (!user) return;

    // Create socket instance but don't connect immediately
    const socket = io(SOCKET_URL, {
      autoConnect: false,
      reconnectionAttempts: 5,
      timeout: 10000,
      transports: ['websocket', 'polling']
    });

    socketRef.current = socket;

    // Setup Listeners BEFORE connecting to avoid race conditions
    socket.on('connect', () => {
      console.log('Socket Connected:', socket.id);
      setSocketConnected(true);
    });

    socket.on('disconnect', () => {
      setSocketConnected(false);
    });

    socket.on('room_updated', (room: Room) => {
      console.log('Room Updated:', room);
      setCurrentRoom(room);
      setView(ViewState.CREATE_ROOM);
    });

    socket.on('game_started', () => {
      setView(ViewState.GAME);
    });

    socket.on('error', (msg: string) => {
      alert(`Server Error: ${msg}`);
    });

    socket.on('connect_error', (err) => {
      console.warn('Socket Connection Error:', err.message);
      setSocketConnected(false);
    });

    // Start connection
    socket.connect();

    return () => {
      if (socket.connected) {
        socket.disconnect();
      }
    };
  }, [user?.id]);

  // Auth & Profile Logic
  useEffect(() => {
    const initAuth = async () => {
      const { data: { session: initialSession } } = await supabase.auth.getSession();
      setSession(initialSession);
      if (initialSession) {
        fetchProfile(initialSession.user.id);
      } else {
        setLoading(false);
      }
    };
    initAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, newSession) => {
      setSession(newSession);
      if (newSession) {
        fetchProfile(newSession.user.id);
      } else {
        setUser(null);
        setView(ViewState.AUTH);
        setLoading(false);
      }
    });
    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (userId: string) => {
    try {
      const { data, error } = await supabase.from('profiles').select('*').eq('id', userId).single();
      if (data) {
        setUser({
          id: data.id,
          name: data.name,
          avatarUrl: data.avatar_url,
          coins: data.coins,
          level: data.level,
          stats: data.stats || DEFAULT_STATS
        });
        setView(prev => prev === ViewState.AUTH ? ViewState.LOBBY : prev);
      }
    } catch (err) {
      console.error('Profile fetch failed:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateRoom = () => {
    if (!user) return;
    const roomCode = Math.random().toString(36).substring(2, 8).toUpperCase();

    setGameMode('FRIEND');

    if (socketConnected && socketRef.current) {
      socketRef.current.emit('create_room', { user, roomCode });
    } else {
      // Offline fallback: Immediately go to lobby
      const localRoom: Room = {
        code: roomCode,
        hostId: user.id,
        participants: [{
          id: user.id,
          name: user.name,
          avatarUrl: user.avatarUrl,
          isHost: true,
          isReady: true
        }]
      };
      setCurrentRoom(localRoom);
      setView(ViewState.CREATE_ROOM);
    }
  };

  const handleJoinRoom = (roomCode: string) => {
    if (!user || !roomCode) return;
    const cleanCode = roomCode.trim().toUpperCase();

    if (socketConnected && socketRef.current) {
      socketRef.current.emit('join_room', { user, roomCode: cleanCode });
    } else {
      alert("Unable to join: Multiplayer server is offline. Check your internet connection.");
    }
  };

  const handleStartGame = () => {
    if (socketConnected && socketRef.current && currentRoom) {
      socketRef.current.emit('start_game', currentRoom.code);
    } else {
      setView(ViewState.GAME);
    }
  };

  const handleSetView = (newView: ViewState) => {
    if (newView === ViewState.PLAYING_COMPUTER) {
      setGameMode('COMPUTER');
      setCurrentRoom(null);
      setView(ViewState.GAME);
    } else if (newView === ViewState.CREATE_ROOM) {
      handleCreateRoom();
    } else {
      setView(newView);
    }
  };

  const syncProfile = (updates: Partial<User>) => {
    setUser(prev => prev ? { ...prev, ...updates } : null);
    if (user) supabase.from('profiles').update(updates).eq('id', user.id);
  };

  if (loading) {
    return (
      <div className="fixed inset-0 bg-ludo-dark flex items-center justify-center z-[200]">
        <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: "linear" }} 
          className="w-10 h-10 border-2 border-ludo-red border-t-transparent rounded-full" />
      </div>
    );
  }

  return (
    <div className="relative w-full h-screen bg-ludo-dark text-white overflow-hidden font-sans">
      <Background />
      <AnimatePresence>
        {user && view !== ViewState.GAME && view !== ViewState.AUTH && (
          <TopBar user={user} onOpenWallet={() => setView(ViewState.WALLET)} onOpenSettings={() => {}} onOpenProfile={() => setIsProfileOpen(true)} />
        )}
      </AnimatePresence>

      <main className="relative w-full h-full flex flex-col z-10">
        <AnimatePresence mode="wait">
          {view === ViewState.AUTH ? (
            <AuthPage key="auth" onLogin={() => {}} />
          ) : view === ViewState.GAME && user ? (
            <GameScreen 
              key="game" user={user} 
              onExit={() => { setView(ViewState.LOBBY); setCurrentRoom(null); }} 
              vsComputer={gameMode === 'COMPUTER'}
              participants={currentRoom?.participants}
              roomCode={currentRoom?.code}
              socket={socketRef.current}
            />
          ) : view === ViewState.WALLET && user ? (
            <WalletPage key="wallet" user={user} onClose={() => setView(ViewState.LOBBY)} onOpenSpin={() => setIsSpinWheelOpen(true)} />
          ) : view === ViewState.TOURNAMENT && user ? (
            <TournamentPage key="tournament" user={user} onClose={() => setView(ViewState.LOBBY)} />
          ) : (
            <Lobby 
              key="lobby" view={view} setView={handleSetView} onOpenDaily={() => setIsDailyRewardOpen(true)} 
              currentRoom={currentRoom} onJoinRoom={handleJoinRoom} onStartGame={handleStartGame}
              userId={user?.id} socketConnected={socketConnected}
              onSimulateRoom={() => handleCreateRoom()}
            />
          )}
        </AnimatePresence>
      </main>

      {user && (
        <>
          <SpinWheel isOpen={isSpinWheelOpen} onClose={() => setIsSpinWheelOpen(false)} 
            onReward={(amt) => syncProfile({ coins: user.coins + amt })}
            onDeduct={(amt) => { if (user.coins >= amt) { syncProfile({ coins: user.coins - amt }); return true; } return false; }}
            userCoins={user.coins} />
          <DailyRewardOverlay isOpen={isDailyRewardOpen} onClose={() => setIsDailyRewardOpen(false)} onClaim={(amt) => syncProfile({ coins: user.coins + amt })} />
          <ProfileOverlay isOpen={isProfileOpen} user={user} onClose={() => setIsProfileOpen(false)} onLogout={() => supabase.auth.signOut()} onUpdateUser={syncProfile} />
        </>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
