const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const cors = require('cors');

const app = express();
app.use(cors());

const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: "*",
    methods: ["GET", "POST"]
  },
  pingTimeout: 10000,
  pingInterval: 5000
});

const rooms = new Map();

io.on('connection', (socket) => {
  console.log('User connected:', socket.id);

  socket.on('create_room', ({ user, roomCode }) => {
    const room = {
      code: roomCode,
      hostId: user.id,
      participants: [{
        id: user.id,
        name: user.name,
        avatarUrl: user.avatarUrl,
        isHost: true,
        isReady: true,
        socketId: socket.id
      }],
      gameState: null
    };
    rooms.set(roomCode, room);
    socket.join(roomCode);
    socket.emit('room_updated', room);
    console.log(`Room created: ${roomCode} by ${user.name}`);
  });

  socket.on('join_room', ({ user, roomCode }) => {
    const room = rooms.get(roomCode);
    if (!room) {
      socket.emit('error', 'Room not found. Check the host code.');
      return;
    }
    if (room.participants.length >= 4) {
      socket.emit('error', 'Room is full');
      return;
    }

    // Use user ID to check if already in room, update socket ID if they reconnected
    const existingIndex = room.participants.findIndex(p => p.id === user.id);
    if (existingIndex === -1) {
        const participant = {
          id: user.id,
          name: user.name,
          avatarUrl: user.avatarUrl,
          isHost: false,
          isReady: true,
          socketId: socket.id
        };
        room.participants.push(participant);
    } else {
        room.participants[existingIndex].socketId = socket.id;
    }

    socket.join(roomCode);
    // Broadcast to EVERYONE in the room including the joiner
    io.to(roomCode).emit('room_updated', room);
    console.log(`${user.name} joined room: ${roomCode}`);
  });

  socket.on('start_game', (roomCode) => {
    const room = rooms.get(roomCode);
    if (room && room.participants.length === 4) {
      io.to(roomCode).emit('game_started');
    } else if (room) {
      socket.emit('error', 'Exactly 4 players required to start Homiies.');
    }
  });

  socket.on('dice_rolled', ({ roomCode, value, playerIndex }) => {
    io.to(roomCode).emit('sync_dice', { value, playerIndex });
  });

  socket.on('move_pawn', ({ roomCode, pawnId, finalLocation, playerIndex }) => {
    io.to(roomCode).emit('sync_move', { pawnId, finalLocation, playerIndex });
  });

  socket.on('next_turn', ({ roomCode, nextIndex }) => {
    io.to(roomCode).emit('sync_turn', nextIndex);
  });

  socket.on('disconnect', () => {
    console.log('User disconnected:', socket.id);
    rooms.forEach((room, code) => {
      const index = room.participants.findIndex(p => p.socketId === socket.id);
      if (index !== -1) {
        room.participants.splice(index, 1);
        if (room.participants.length === 0) {
          rooms.delete(code);
        } else {
          if (index === 0 && room.participants.length > 0) {
            room.hostId = room.participants[0].id;
            room.participants[0].isHost = true;
          }
          io.to(code).emit('room_updated', room);
        }
      }
    });
  });
});

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`Socket.io server running on port ${PORT}`);
});

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Background } from './components/Background';
import { Lobby } from './components/Lobby';
import { TopBar } from './components/TopBar';
import { SpinWheel } from './components/SpinWheel';
import { DailyRewardOverlay } from './components/DailyRewardOverlay';
import { WalletPage } from './components/WalletPage';
import { GameScreen } from './components/Game/GameScreen';
import { ProfileOverlay } from './components/ProfileOverlay';
import { AuthPage } from './components/AuthPage';
import { TournamentPage } from './components/TournamentPage';
import { ViewState, User, UserStats, Room, RoomParticipant } from './types';
import { motion, AnimatePresence } from 'framer-motion';
import { supabase } from './lib/supabase';
import { io, Socket } from 'socket.io-client';

const DEFAULT_STATS: UserStats = {
  gamesWon: 0,
  gamesLost: 0,
  winStreak: 0,
  tokensCaptured: 0,
  tournamentsWon: 0
};

// Robust socket URL detection
const SOCKET_URL = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
  ? 'http://localhost:3000' 
  : `${window.location.protocol}//${window.location.hostname}:3000`;

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>(ViewState.AUTH);
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const [isSpinWheelOpen, setIsSpinWheelOpen] = useState(false);
  const [isDailyRewardOpen, setIsDailyRewardOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [gameMode, setGameMode] = useState<'FRIEND' | 'COMPUTER'>('FRIEND');

  // Room & Socket State
  const [currentRoom, setCurrentRoom] = useState<Room | null>(null);
  const [socketConnected, setSocketConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const socketRef = useRef<Socket | null>(null);

  // Function to initiate socket connection ONLY when needed
  const initiateSocket = useCallback(() => {
    if (socketRef.current?.connected) return;
    if (!user) return;

    setIsConnecting(true);

    const socket = io(SOCKET_URL, {
      reconnectionAttempts: 5,
      timeout: 10000,
      transports: ['websocket', 'polling']
    });

    socketRef.current = socket;

    socket.on('connect', () => {
      console.log('Socket Established:', socket.id);
      setSocketConnected(true);
      setIsConnecting(false);
    });

    socket.on('disconnect', () => {
      setSocketConnected(false);
    });

    socket.on('room_updated', (room: Room) => {
      setCurrentRoom(room);
      setView(ViewState.CREATE_ROOM);
    });

    socket.on('game_started', () => {
      setView(ViewState.GAME);
    });

    socket.on('error', (msg: string) => {
      alert(`Multiplayer Error: ${msg}`);
      setIsConnecting(false);
    });

    socket.on('connect_error', () => {
      console.warn('Could not connect to multiplayer server.');
      setSocketConnected(false);
      setIsConnecting(false);
    });
  }, [user]);

  // Clean up socket on unmount
  useEffect(() => {
    return () => {
      socketRef.current?.disconnect();
    };
  }, []);

  // Auth & Profile Logic
  useEffect(() => {
    const initAuth = async () => {
      const { data: { session: initialSession } } = await supabase.auth.getSession();
      setSession(initialSession);
      if (initialSession) {
        fetchProfile(initialSession.user.id);
      } else {
        setLoading(false);
      }
    };
    initAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, newSession) => {
      setSession(newSession);
      if (newSession) {
        fetchProfile(newSession.user.id);
      } else {
        setUser(null);
        setView(ViewState.AUTH);
        setLoading(false);
        socketRef.current?.disconnect();
      }
    });
    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (userId: string) => {
    try {
      const { data, error } = await supabase.from('profiles').select('*').eq('id', userId).single();
      if (data) {
        setUser({
          id: data.id,
          name: data.name,
          avatarUrl: data.avatar_url,
          coins: data.coins,
          level: data.level,
          stats: data.stats || DEFAULT_STATS
        });
        setView(prev => prev === ViewState.AUTH ? ViewState.LOBBY : prev);
      }
    } catch (err) {
      console.error('Profile fetch failed:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateRoom = () => {
    if (!user) return;
    const roomCode = Math.random().toString(36).substring(2, 8).toUpperCase();
    setGameMode('FRIEND');

    if (socketConnected && socketRef.current) {
      socketRef.current.emit('create_room', { user, roomCode });
    } else {
      // Fallback
      const localRoom: Room = {
        code: roomCode,
        hostId: user.id,
        participants: [{
          id: user.id,
          name: user.name,
          avatarUrl: user.avatarUrl,
          isHost: true,
          isReady: true
        }]
      };
      setCurrentRoom(localRoom);
      setView(ViewState.CREATE_ROOM);
    }
  };

  const handleJoinRoom = (roomCode: string) => {
    if (!user || !roomCode) return;
    const cleanCode = roomCode.trim().toUpperCase();

    if (socketConnected && socketRef.current) {
      socketRef.current.emit('join_room', { user, roomCode: cleanCode });
    } else {
      alert("Multiplayer server offline. Please try again later.");
    }
  };

  const handleStartGame = () => {
    if (socketConnected && socketRef.current && currentRoom) {
      socketRef.current.emit('start_game', currentRoom.code);
    } else {
      setView(ViewState.GAME);
    }
  };

  const handleSetView = (newView: ViewState) => {
    if (newView === ViewState.FRIEND_OPTIONS) {
      initiateSocket();
      setView(ViewState.FRIEND_OPTIONS);
    } else if (newView === ViewState.PLAYING_COMPUTER) {
      setGameMode('COMPUTER');
      setCurrentRoom(null);
      setView(ViewState.GAME);
    } else if (newView === ViewState.CREATE_ROOM) {
      handleCreateRoom();
    } else {
      setView(newView);
    }
  };

  const syncProfile = (updates: Partial<User>) => {
    setUser(prev => prev ? { ...prev, ...updates } : null);
    if (user) supabase.from('profiles').update(updates).eq('id', user.id);
  };

  if (loading) {
    return (
      <div className="fixed inset-0 bg-ludo-dark flex items-center justify-center z-[200]">
        <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: "linear" }} 
          className="w-10 h-10 border-2 border-ludo-red border-t-transparent rounded-full" />
      </div>
    );
  }

  return (
    <div className="relative w-full h-screen bg-ludo-dark text-white overflow-hidden font-sans">
      <Background />
      <AnimatePresence>
        {user && view !== ViewState.GAME && view !== ViewState.AUTH && (
          <TopBar user={user} onOpenWallet={() => setView(ViewState.WALLET)} onOpenSettings={() => {}} onOpenProfile={() => setIsProfileOpen(true)} />
        )}
      </AnimatePresence>

      <main className="relative w-full h-full flex flex-col z-10">
        <AnimatePresence mode="wait">
          {view === ViewState.AUTH ? (
            <AuthPage key="auth" onLogin={() => {}} />
          ) : view === ViewState.GAME && user ? (
            <GameScreen 
              key="game" user={user} 
              onExit={() => { setView(ViewState.LOBBY); setCurrentRoom(null); }} 
              vsComputer={gameMode === 'COMPUTER'}
              participants={currentRoom?.participants}
              roomCode={currentRoom?.code}
              socket={socketRef.current}
            />
          ) : view === ViewState.WALLET && user ? (
            <WalletPage key="wallet" user={user} onClose={() => setView(ViewState.LOBBY)} onOpenSpin={() => setIsSpinWheelOpen(true)} />
          ) : view === ViewState.TOURNAMENT && user ? (
            <TournamentPage key="tournament" user={user} onClose={() => setView(ViewState.LOBBY)} />
          ) : (
            <Lobby 
              key="lobby" view={view} setView={handleSetView} onOpenDaily={() => setIsDailyRewardOpen(true)} 
              currentRoom={currentRoom} onJoinRoom={handleJoinRoom} onStartGame={handleStartGame}
              userId={user?.id} socketConnected={socketConnected} isConnecting={isConnecting}
              onSimulateRoom={() => handleCreateRoom()}
            />
          )}
        </AnimatePresence>
      </main>

      {user && (
        <>
          <SpinWheel isOpen={isSpinWheelOpen} onClose={() => setIsSpinWheelOpen(false)} 
            onReward={(amt) => syncProfile({ coins: user.coins + amt })}
            onDeduct={(amt) => { if (user.coins >= amt) { syncProfile({ coins: user.coins - amt }); return true; } return false; }}
            userCoins={user.coins} />
          <DailyRewardOverlay isOpen={isDailyRewardOpen} onClose={() => setIsDailyRewardOpen(false)} onClaim={(amt) => syncProfile({ coins: user.coins + amt })} />
          <ProfileOverlay isOpen={isProfileOpen} user={user} onClose={() => setIsProfileOpen(false)} onLogout={() => supabase.auth.signOut()} onUpdateUser={syncProfile} />
        </>
      )}
    </div>
  );
};

export default App;

